     2|
     3|export async function middleware(request: NextRequest) {
     4|  const pathname = request.nextUrl.pathname;
     5|
     6|  // Only check auth for /admin routes  
     7|  if (!pathname.startsWith('/admin')) {
     8|    return NextResponse.next({ request });
     9|  }
    10|
    11|  // Allow login page and static assets through
    12|  if (pathname === '/admin/ingreso' ||
    13|      pathname.startsWith('/_next/') ||
    14|      pathname.startsWith('/api/')) {
    15|    return NextResponse.next({ request });
    16|  }
    17|
    18|  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
    19|  const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
    20|
    21|  // Skip auth if env is missing (self-hosted mode)
    22|  if (!supabaseUrl || !supabaseAnonKey || !supabaseUrl.includes('supabase.co')) {
    23|    return NextResponse.next({ request });
    24|  }
    25|
    26|  try {
    27|    const { createServerClient } = await import('@supabase/ssr');
    28|    let supabaseResponse = NextResponse.next({ request });
    29|
    30|    const supabase = createServerClient(supabaseUrl, supabaseAnonKey, {
    31|      cookies: {
    32|        getAll() { return request.cookies.getAll(); },
    33|        setAll(cookiesToSet) {
    34|          cookiesToSet.forEach(({ name, value }) => request.cookies.set(name, value));
    35|          supabaseResponse = NextResponse.next({ request });
    36|          cookiesToSet.forEach(({ name, value, options }) =>
    37|            supabaseResponse.cookies.set(name, value, options)
    38|          );
    39|        },
    40|      },
    41|    });
    42|
    43|    const { data: { user } } = await supabase.auth.getUser();
    44|
    45|    if (!user) {
    46|      const url = request.nextUrl.clone();
    47|      url.pathname = '/admin/ingreso';
    48|      url.searchParams.set('redirect', pathname);
    49|      return NextResponse.redirect(url);
    50|    }
    51|
    52|    return supabaseResponse;
    53|  } catch {
    54|    return NextResponse.next({ request });
    55|  }
    56|}
    57|
    58|export const config = {
    59|  matcher: ['/admin/:path*'],
    60|};
