{"content": "     1|// @ts-nocheck
     2|import { NextRequest, NextResponse } from 'next/server';
     3|import { createClient } from '@/lib/supabase/server';
     4|
     5|export async function POST(request: NextRequest) {
     6|  try {
     7|    const supabase = await createClient();
     8|
     9|    // Get current user if authenticated
    10|    const { data: { user } } = await supabase.auth.getUser();
    11|
    12|    let orderData: any;
    13|    let receiptFile: File | null = null;
    14|    const contentType = request.headers.get('content-type') || '';
    15|
    16|    if (contentType.includes('multipart/form-data')) {
    17|      const formData = await request.formData();
    18|      orderData = JSON.parse(formData.get('order_data') as string);
    19|      receiptFile = formData.get('receipt') as File | null;
    20|    } else {
    21|      orderData = await request.json();
    22|    }
    23|
    24|    // Validate required fields
    25|    if (!orderData.customer_name?.trim()) {
    26|      return NextResponse.json({ error: 'El nombre es obligatorio' }, { status: 400 });
    27|    }
    28|    if (!orderData.customer_phone?.trim()) {
    29|      return NextResponse.json({ error: 'El teléfono es obligatorio' }, { status: 400 });
    30|    }
    31|    if (!orderData.items?.length) {
    32|      return NextResponse.json({ error: 'El carrito está vacío' }, { status: 400 });
    33|    }
    34|    if (!orderData.shipping_address?.address || !orderData.shipping_address?.city) {
    35|      return NextResponse.json({ error: 'La dirección de envío es obligatoria' }, { status: 400 });
    36|    }
    37|
    38|    // Validate stock
    39|    for (const item of orderData.items) {
    40|      const { data: product, error: prodErr } = await supabase
    41|        .from('products')
    42|        .select('id, name, stock_quantity')
    43|        .eq('id', item.product_id)
    44|        .single();
    45|
    46|      if (prodErr || !product) {
    47|        return NextResponse.json({
    48|          error: `Producto no encontrado: ${item.name}`,
    49|          code: 'PRODUCT_NOT_FOUND',
    50|        }, { status: 400 });
    51|      }
    52|
    53|      if ((product.stock_quantity ?? 0) < item.quantity) {
    54|        return NextResponse.json({
    55|          error: `Stock insuficiente para "${product.name}". Disponible: ${product.stock_quantity}`,
    56|          code: 'INSUFFICIENT_STOCK',
    57|          items: [{ product_id: item.product_id, name: product.name, available: product.stock_quantity }],
    58|        }, { status: 400 });
    59|      }
    60|    }
    61|
    62|    // Create order
    63|    const orderPayload: any = {
    64|      status: 'pending',
    65|      subtotal: orderData.subtotal,
    66|      shipping_cost: orderData.shipping_cost || 0,
    67|      discount_amount: orderData.discount_amount || 0,
    68|      total: orderData.total,
    69|      payment_method: orderData.payment_method,
    70|      shipping_address: orderData.shipping_address,
    71|      notes: orderData.notes || null,
    72|    };
    73|
    74|    if (user) {
    75|      orderPayload.customer_id = user.id;
    76|    } else {
    77|      orderPayload.guest_email = orderData.customer_email || null;
    78|      orderPayload.guest_phone = orderData.customer_phone || null;
    79|    }
    80|
    81|    // Validate coupon if provided
    82|    if (orderData.coupon_code) {
    83|      const { data: couponResult } = await supabase.rpc('validate_coupon', {
    84|        coupon_code: orderData.coupon_code,
    85|        order_subtotal: BigInt(orderData.subtotal),
    86|      });
    87|
    88|      if (couponResult && !couponResult.valid) {
    89|        return NextResponse.json({ error: couponResult.error || 'Cupón inválido' }, { status: 400 });
    90|      }
    91|    }
    92|
    93|    const { data: order, error: orderError } = await supabase
    94|      .from('orders')
    95|      .insert(orderPayload)
    96|      .select('id, order_number')
    97|      .single();
    98|
    99|    if (orderError) {
   100|      console.error('[checkout] order insert error:', orderError);
   101|      return NextResponse.json({ error: 'Error al crear el pedido. Intentá de nuevo.' }, { status: 500 });
   102|    }
   103|
   104|    // Insert order items
   105|    const orderItems = orderData.items.map((item: any) => ({
   106|      order_id: order.id,
   107|      product_id: item.product_id,
   108|      product_name: item.name,
   109|      quantity: item.quantity,
   110|      unit_price: item.price,
   111|      line_total: item.price * item.quantity,
   112|    }));
   113|
   114|    const { error: itemsError } = await supabase
   115|      .from('order_items')
   116|      .insert(orderItems);
   117|
   118|    if (itemsError) {
   119|      console.error('[checkout] items insert error:', itemsError);
   120|      // Attempt cleanup
   121|      await supabase.from('orders').delete().eq('id', order.id);
   122|      return NextResponse.json({ error: 'Error al guardar los items del pedido.' }, { status: 500 });
   123|    }
   124|
   125|    // Decrement stock
   126|    for (const item of orderData.items) {
   127|      await supabase.rpc('decrement_stock', {
   128|        product_id: item.product_id,
   129|        quantity: item.quantity,
   130|      });
   131|    }
   132|
   133|    // Handle receipt upload
   134|    if (receiptFile && orderData.payment_method === 'bank_transfer') {
   135|      const buffer = Buffer.from(await receiptFile.arrayBuffer());
   136|      const filePath = `orders/${order.id}/${receiptFile.name}`;
   137|
   138|      const { error: uploadError } = await supabase.storage
   139|        .from('receipts')
   140|        .upload(filePath, buffer, {
   141|          contentType: receiptFile.type,
   142|          upsert: false,
   143|        });
   144|
   145|      if (!uploadError) {
   146|        const { data: { publicUrl } } = supabase.storage
   147|          .from('receipts')
   148|          .getPublicUrl(filePath);
   149|
   150|        await supabase.from('bank_transfer_receipts').insert({
   151|          order_id: order.id,
   152|          image_url: publicUrl,
   153|        });
   154|      } else {
   155|        console.error('[checkout] receipt upload error:', uploadError);
   156|      }
   157|    }
   158|
   159|    // Save customer info to profile if authenticated
   160|    if (user && orderData.customer_name) {
   161|      await supabase.from('customers').upsert({
   162|        id: user.id,
   163|        full_name: orderData.customer_name,
   164|        phone: orderData.customer_phone,
   165|        email: orderData.customer_email || user.email,
   166|      }, { onConflict: 'id' });
   167|    }
   168|
   169|    return NextResponse.json({
   170|      success: true,
   171|      order: { id: order.id, order_number: order.order_number },
   172|    });
   173|
   174|  } catch (error) {
   175|    console.error('[checkout] unexpected error:', error);
   176|    return NextResponse.json({ error: 'Error inesperado. Intentá de nuevo.' }, { status: 500 });
   177|  }
   178|}
   179|", "total_lines": 178, "file_size": 5984, "truncated": false, "is_binary": false, "is_image": false}

