     2| * JWT authentication utilities for the Refugio Animal Paraguay frontend.
     3| *
     4| * Handles token storage (in-memory + sessionStorage), parsing,
     5| * and expiration checking. Tokens are injected into API requests
     6| * via the api client (lib/api.ts).
     7| */
     8|
     9|import type { TokenPayload, UserRole } from "@/types/api";
    10|
    11|const TOKEN_STORAGE_KEY="refugi...oken";
    12|
    13|// In-memory token for SSR safety (sessionStorage not available server-side)
    14|let memoryToken: string | null = null;
    15|
    16|/**
    17| * Store the access token after login.
    18| * Uses both in-memory and sessionStorage for persistence across page loads.
    19| */
    20|export function setAccessToken(token: string): void {
    21|  memoryToken = token;
    22|  if (typeof window !== "undefined") {
    23|    sessionStorage.setItem(TOKEN_STORAGE_KEY, token);
    24|  }
    25|}
    26|
    27|/**
    28| * Retrieve the current access token.
    29| * Falls back to sessionStorage if in-memory token is cleared (e.g., after HMR).
    30| */
    31|export function getAccessToken(): string | null {
    32|  if (memoryToken) {
    33|    return memoryToken;
    34|  }
    35|  if (typeof window !== "undefined") {
    36|    const stored = sessionStorage.getItem(TOKEN_STORAGE_KEY);
    37|    if (stored) {
    38|      memoryToken = stored;
    39|      return stored;
    40|    }
    41|  }
    42|  return null;
    43|}
    44|
    45|/**
    46| * Remove the access token (logout).
    47| */
    48|export function clearAccessToken(): void {
    49|  memoryToken = null;
    50|  if (typeof window !== "undefined") {
    51|    sessionStorage.removeItem(TOKEN_STORAGE_KEY);
    52|  }
    53|}
    54|
    55|/**
    56| * Decode a JWT token payload without verification.
    57| * Verification happens server-side; this is for UI display only.
    58| */
    59|export function decodeToken(token: string): TokenPayload | null {
    60|  try {
    61|    const parts = token.split(".");
    62|    if (parts.length !== 3) return null;
    63|    const payload = JSON.parse(atob(parts[1]));
    64|    return payload as TokenPayload;
    65|  } catch {
    66|    return null;
    67|  }
    68|}
    69|
    70|/**
    71| * Check if the current token is expired.
    72| */
    73|export function isTokenExpired(token: string): boolean {
    74|  const payload = decodeToken(token);
    75|  if (!payload?.exp) return true;
    76|  // Allow 30-second buffer for clock skew
    77|  const CLOCK_SKEW_BUFFER_SECONDS = 30;
    78|  return Date.now() / 1000 > payload.exp - CLOCK_SKEW_BUFFER_SECONDS;
    79|}
    80|
    81|/**
    82| * Check if the user is currently authenticated with a valid token.
    83| */
    84|export function isAuthenticated(): boolean {
    85|  const token = getAccessToken();
    86|  if (!token) return false;
    87|  return !isTokenExpired(token);
    88|}
    89|
    90|/**
    91| * Get the current user's role from the token, if authenticated.
    92| */
    93|export function getCurrentUserRole(): UserRole | null {
    94|  const token = getAccessToken();
    95|  if (!token) return null;
    96|  const payload = decodeToken(token);
    97|  return payload?.role ?? null;
    98|}
    99|
   100|/**
   101| * Get the current user's identifier (sub claim) from the token.
   102| */
   103|export function getCurrentUserId(): string | null {
   104|  const token = getAccessToken();
   105|  if (!token) return null;
   106|  const payload = decodeToken(token);
   107|  return payload?.sub ?? null;
   108|}
