    11|// Simple QR generation using a canvas-based approach
    12|function generateQR(text: string, size = 200): string {
    13|  // Simple QR-like visual — for production use a library like qrcode
    14|  const canvas = document.createElement('canvas');
    15|  canvas.width = size;
    16|  canvas.height = size;
    17|  const ctx = canvas.getContext('2d')!;
    18|  
    19|  // Draw QR-like pattern
    20|  ctx.fillStyle = 'white';
    21|  ctx.fillRect(0, 0, size, size);
    22|  ctx.fillStyle = 'black';
    23|  
    24|  const moduleSize = size / 25;
    25|  const pattern = generateQRPattern(text);
    26|  
    27|  for (let row = 0; row < 25; row++) {
    28|    for (let col = 0; col < 25; col++) {
    29|      if (pattern[row * 25 + col]) {
    30|        ctx.fillRect(col * moduleSize, row * moduleSize, moduleSize, moduleSize);
    31|      }
    32|    }
    33|  }
    34|  
    35|  return canvas.toDataURL('image/png');
