    37|
    38|function generateQRPattern(text: string): boolean[] {
    39|  const pattern: boolean[] = [];
    40|  const hash = text.split('').reduce((acc, char) => acc * 31 + char.charCodeAt(0), 0);
    41|  
    42|  // Fixed finder patterns (corners)
    43|  for (let row = 0; row < 25; row++) {
    44|    for (let col = 0; col < 25; col++) {
    45|      const inTopLeft = row < 7 && col < 7;
    46|      const inTopRight = row < 7 && col > 17;
    47|      const inBottomLeft = row > 17 && col < 7;
    48|      
    49|      if (inTopLeft || inTopRight || inBottomLeft) {
    50|        const isOuter = (row === 0 || row === 6 || col === 0 || col === 6) && !(row === 0 && col === 6);
    51|        const isInner = row >= 2 && row <= 4 && col >= 2 && col <= 4;
    52|        pattern.push(isOuter || isInner);
    53|      } else {
    54|        // Data area — pseudo-random based on hash
    55|        const idx = row * 25 + col;
    56|        pattern.push(((hash >> (idx % 31)) & 1) === 1);
    57|      }
    58|    }
    59|  }
    60|  return pattern;
