// Self-hosted auth API - replaces Supabase GoTrue for this setup
import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/db';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'fun4me-jwt-secret-change-in-production';
const TOKEN_EXPIRY = '7d';

export async function POST(request: NextRequest) {
  try {
    const { email, password } = await request.json();

    if (!email?.trim() || !password) {
      return NextResponse.json(
        { error: 'Email y contraseña son requeridos' },
        { status: 400 }
      );
    }

    const supabase = createClient();

    // Find user by email in customers table
    const { data: customer, error: lookupError } = await supabase
      .from('customers')
      .select('*')
      .eq('email', email.trim().toLowerCase())
      .single();

    if (lookupError || !customer) {
      return NextResponse.json(
        { error: 'Credenciales incorrectas. Verificá tu correo y contraseña.' },
        { status: 401 }
      );
    }

    // Check if password is set
    if (!customer.password_hash) {
      return NextResponse.json(
        { error: 'Esta cuenta usa otro método de inicio de sesión.' },
        { status: 401 }
      );
    }

    // Verify password
    const valid = await bcrypt.compare(password, customer.password_hash);
    if (!valid) {
      return NextResponse.json(
        { error: 'Credenciales incorrectas. Verificá tu correo y contraseña.' },
        { status: 401 }
      );
    }

    // Update last login
    await supabase
      .from('customers')
      .update({ last_login_at: new Date().toISOString() })
      .eq('id', customer.id);

    // Generate JWT
    const token = jwt.sign(
      {
        sub: customer.id,
        email: customer.email,
        role: 'customer',
        iat: Math.floor(Date.now() / 1000),
      },
      JWT_SECRET,
      { expiresIn: TOKEN_EXPIRY }
    );

    return NextResponse.json({
      access_token: token,
      user: {
        id: customer.id,
        email: customer.email,
        full_name: customer.full_name,
        phone: customer.phone,
        display_name: customer.display_name,
        avatar_url: customer.avatar_url,
        roles: customer.roles,
      },
    });
  } catch (error) {
    console.error('[auth/login] error:', error);
    return NextResponse.json(
      { error: 'Error de conexión. Intentá de nuevo más tarde.' },
      { status: 500 }
    );
  }
}
