// Self-hosted auth API - register with password
import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/db';
import bcrypt from 'bcryptjs';

export async function POST(request: NextRequest) {
  try {
    const { email, password, full_name, phone } = await request.json();

    if (!email?.trim()) {
      return NextResponse.json({ error: 'El correo es obligatorio' }, { status: 400 });
    }
    if (!password || password.length < 6) {
      return NextResponse.json({ error: 'La contraseña debe tener al menos 6 caracteres' }, { status: 400 });
    }
    if (!full_name?.trim()) {
      return NextResponse.json({ error: 'El nombre es obligatorio' }, { status: 400 });
    }

    const supabase = createClient();

    // Check if email already exists
    const { data: existing } = await supabase
      .from('customers')
      .select('id')
      .eq('email', email.trim().toLowerCase())
      .single();

    if (existing) {
      return NextResponse.json(
        { error: 'Este correo ya está registrado. Iniciá sesión.' },
        { status: 409 }
      );
    }

    // Hash password
    const password_hash = await bcrypt.hash(password, 12);

    // Generate UUID v4 using crypto
    const id = crypto.randomUUID();

    // Create user
    const { error: insertError } = await supabase.from('customers').insert({
      id,
      email: email.trim().toLowerCase(),
      full_name: full_name.trim(),
      phone: phone?.trim() || null,
      password_hash,
      display_name: full_name.trim().split(' ')[0],
      created_at: new Date().toISOString(),
    });

    if (insertError) {
      console.error('[auth/register] insert error:', insertError);
      return NextResponse.json(
        { error: 'Error al crear la cuenta. Intentá de nuevo.' },
        { status: 500 }
      );
    }

    return NextResponse.json({
      success: true,
      message: 'Cuenta creada exitosamente. Ya podés iniciar sesión.',
    });
  } catch (error) {
    console.error('[auth/register] error:', error);
    return NextResponse.json(
      { error: 'Error de conexión. Intentá de nuevo más tarde.' },
      { status: 500 }
    );
  }
}
