    it('should login with valid credentials', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: TEST_USER.email, password: TEST_USER.password }),
      });
      expect(res.status).toBe(200);
      const data = await res.json();

      expect(data.access_token).toBeTruthy();
      expect(typeof data.access_token).toBe('string');
      expect(data.access_token.split('.').length).toBe(3); // JWT format

      expect(data.user).toBeTruthy();
      expect(data.user.email).toBe(TEST_USER.email);
      expect(data.user.full_name).toBe(TEST_USER.full_name);

      accessToken = data.access_token;
      userId = data.user.id;
    });

    it('should return consistent user data on repeat login', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: TEST_USER.email, password: TEST_USER.password }),
      });
      expect(res.status).toBe(200);
      const data = await res.json();
      expect(data.user.id).toBe(userId);
    });
  });

  // ============= GET CURRENT USER / ME =============

  describe('GET /api/auth/me', () => {
    it('should reject without token', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/me`);
      expect(res.status).toBe(401);
    });

    it('should reject invalid token', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/me`, {
        headers: { Authorization: 'Bearer invalid-token-here' },
      });
      expect(res.status).toBe(401);
    });

    it('should return user data with valid token', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/me`, {
        headers: { Authorization: `Bearer ${accessToken}` },
      });
      expect(res.status).toBe(200);
      const data = await res.json();
      expect(data.email).toBe(TEST_USER.email);
      expect(data.full_name).toBe(TEST_USER.full_name);
    });
  });

  // ============= PERSISTENCE (session survival) =============

  describe('Session persistence', () => {
    it('should survive multiple sequential requests', async () => {
      for (let i = 0; i < 5; i++) {
        const res = await fetch(`${BASE_URL}/api/auth/me`, {
          headers: { Authorization: `Bearer ${accessToken}` },
        });
        expect(res.status).toBe(200);
      }
    });
  });

  // ============= EDGE CASES =============

  describe('Edge cases', () => {
    it('should handle email with spaces', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: `  ${TEST_USER.email}  `, password: TEST_USER.password }),
      });
      expect(res.status).toBe(200);
    });

    it('should handle email case insensitivity', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: TEST_USER.email.toUpperCase(), password: TEST_USER.password }),
      });
      expect(res.status).toBe(200);
    });

    it('should reject SQL injection attempt in email', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: "' OR 1=1 --", password: 'anything' }),
      });
      expect(res.status).toBe(401); // Must not auth
    });

    it('should reject email with no password', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: TEST_USER.email }),
      });
      expect(res.status).toBe(400);
    });

    it('should reject XSS in full_name during registration', async () => {
      const res = await fetch(`${BASE_URL}/api/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: `xss-${Date.now()}@test.com`,
          password: 'ValidPass123',
          full_name: '<script>alert("xss")</script>',
        }),
      });
      expect(res.status).toBe(200); // Stored as-is (escaped on render)
    });
  });
});

