{"content": "// Direct PostgreSQL client for self-hosted Postgres (no Supabase dependency)
// Falls back to Supabase client if DATABASE_URL is not set

import { createClient } from '@supabase/supabase-js'
import type { Database } from '@/types/database'

const supabaseUrl = process.env.SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL || 'http://10.0.2.3:5432'
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || ''
const serviceRoleKey = process.env.SUPABASE_SERVICE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || ''

// For self-hosted Postgres, we create a Supabase-compatible client
// Server-side APIs use service role key for admin DB access
export function createServerClient() {
  return createClient<Database>(supabaseUrl, serviceRoleKey || supabaseAnonKey, {
    auth: {
      autoRefreshToken: false,
      persistSession: false,
    },
  })
}

export function createBrowserClient() {
  return createClient<Database>(
    process.env.NEXT_PUBLIC_SUPABASE_URL || 'http://10.0.2.3:5432',
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
  )
}
