// Self-hosted auth API - replaces Supabase GoTrue for this setup
import { NextRequest, NextResponse } from 'next/server';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'fun4me-jwt-secret-change-in-production';
const TOKEN_EXPIRY = '7d';

// Direct PostgreSQL connection for auth queries
// Supabase-js REST client can't connect to raw Postgres (port 5432)
async function query(sql, params = []) {
  const { Pool } = require('pg');
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL || '[REDACTED_POSTGRES_URI]',
    max: 5,
    connectionTimeoutMillis: 5000,
  });
  try {
    const client = await pool.connect();
    try {
      const result = await client.query(sql, params);
      return result.rows;
    } finally {
      client.release();
    }
  } finally {
    await pool.end();
  }
}

export async function POST(request: NextRequest) {
  try {
    const { email, password } = await request.json();

    if (!email?.trim() || !password) {
      return NextResponse.json(
        { error: 'Email y contraseña son requeridos' },
        { status: 400 }
      );
    }

    const normalizedEmail = email.trim().toLowerCase();

    // Find user by email
    const customers = await query(
      'SELECT * FROM customers WHERE email = $1 LIMIT 1',
      [normalizedEmail]
    );

    if (!customers.length) {
      return NextResponse.json(
        { error: 'Credenciales incorrectas. Verificá tu correo y contraseña.' },
        { status: 401 }
      );
    }

    const customer = customers[0];

    // Check if password is set
    if (!customer.password_hash) {
      return NextResponse.json(
        { error: 'Esta cuenta usa otro método de inicio de sesión.' },
        { status: 401 }
      );
    }

    // Verify password using bcrypt
    const bcrypt = require('bcryptjs');
    const valid = await bcrypt.compare(password, customer.password_hash);
    if (!valid) {
      return NextResponse.json(
        { error: 'Credenciales incorrectas. Verificá tu correo y contraseña.' },
        { status: 401 }
      );
    }

    // Update last login
    await query(
      'UPDATE customers SET last_login_at = NOW() WHERE id = $1',
      [customer.id]
    );

    // Generate JWT
    const token = jwt.sign(
      {
        sub: customer.id,
        email: customer.email,
        role: 'customer',
      },
      JWT_SECRET,
      { expiresIn: TOKEN_EXPIRY }
    );

    return NextResponse.json({
      access_token: token,
      user: {
        id: customer.id,
        email: customer.email,
        full_name: customer.full_name,
        phone: customer.phone,
        display_name: customer.display_name,
        avatar_url: customer.avatar_url,
        roles: customer.roles,
      },
    });
  } catch (error) {
    console.error('[auth/login] error:', error);
    return NextResponse.json(
      { error: 'Error de conexión. Intentá de nuevo más tarde.' },
      { status: 500 }
    );
  }
}
