// Self-hosted auth API - register with password
import { NextRequest, NextResponse } from 'next/server';

async function query(sql, params = []) {
  const { Pool } = require('pg');
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL || '[REDACTED_POSTGRES_URI]',
    max: 5,
    connectionTimeoutMillis: 5000,
  });
  try {
    const client = await pool.connect();
    try {
      const result = await client.query(sql, params);
      return result.rows;
    } finally {
      client.release();
    }
  } finally {
    await pool.end();
  }
}

function sanitizePhone(phone) {
  if (!phone?.trim()) return null;
  // Keep only digits and +
  return phone.trim().replace(/[^0-9+]/g, '');
}

export async function POST(request: NextRequest) {
  try {
    const { email, password, full_name, phone } = await request.json();

    if (!email?.trim()) {
      return NextResponse.json({ error: 'El correo es obligatorio' }, { status: 400 });
    }
    if (!password || password.length < 6) {
      return NextResponse.json({ error: 'La contraseña debe tener al menos 6 caracteres' }, { status: 400 });
    }
    if (!full_name?.trim()) {
      return NextResponse.json({ error: 'El nombre es obligatorio' }, { status: 400 });
    }

    const normalizedEmail = email.trim().toLowerCase();

    // Check if email already exists
    const existing = await query(
      'SELECT id FROM customers WHERE email = $1 LIMIT 1',
      [normalizedEmail]
    );

    if (existing.length > 0) {
      return NextResponse.json(
        { error: 'Este correo ya está registrado. Iniciá sesión.' },
        { status: 409 }
      );
    }

    // Hash password
    const bcrypt = require('bcryptjs');
    const password_hash = await bcrypt.hash(password, 12);

    // Generate UUID v4
    const crypto = require('crypto');
    const id = crypto.randomUUID();

    const cleanPhone = sanitizePhone(phone);
    const displayName = full_name.trim().split(' ')[0];
    const now = new Date().toISOString();

    // Create user
    await query(
      `INSERT INTO customers (id, email, full_name, phone, password_hash, display_name, created_at)
       VALUES ($1, $2, $3, $4, $5, $6, $7)`,
      [id, normalizedEmail, full_name.trim(), cleanPhone, password_hash, displayName, now]
    );

    return NextResponse.json({
      success: true,
      message: 'Cuenta creada exitosamente. Ya podés iniciar sesión.',
    });
  } catch (error) {
    console.error('[auth/register] error:', error);
    return NextResponse.json(
      { error: 'Error al crear la cuenta. Intentá de nuevo.' },
      { status: 500 }
    );
  }
}
