// Self-hosted auth API - me (get current user from token)
import { NextRequest, NextResponse } from 'next/server';
import { jwtVerify } from 'jose';

const JWT_SECRET = new TextEncoder().encode(
  process.env.JWT_SECRET || 'fun4me-jwt-secret-change-in-production'
);

async function query(sql, params = []) {
  const { Pool } = require('pg');
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL || '[REDACTED_POSTGRES_URI]',
    max: 5,
    connectionTimeoutMillis: 5000,
  });
  try {
    const client = await pool.connect();
    try {
      const result = await client.query(sql, params);
      return result.rows;
    } finally {
      client.release();
    }
  } finally {
    await pool.end();
  }
}

export async function GET(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.startsWith('Bearer ')
      ? authHeader.slice(7)
      : null;

    if (!token) {
      return NextResponse.json({ error: 'No autorizado' }, { status: 401 });
    }

    const { payload } = await jwtVerify(token, JWT_SECRET);
    const userId = payload.sub;

    const customers = await query('SELECT * FROM customers WHERE id = $1 LIMIT 1', [userId]);

    if (!customers.length) {
      return NextResponse.json({ error: 'Usuario no encontrado' }, { status: 404 });
    }

    const c = customers[0];
    return NextResponse.json({
      id: c.id,
      email: c.email,
      full_name: c.full_name,
      phone: c.phone,
      display_name: c.display_name,
      avatar_url: c.avatar_url,
      roles: c.roles,
    });
  } catch {
    return NextResponse.json({ error: 'Token inválido o expirado' }, { status: 401 });
  }
}
